        callCount++;
    }

    int getCallCount() const { return callCount; }
};

// Class using multiple policies
class SmartCalculator
    : public Logger<SmartCalculator>,
      public Cacheable<SmartCalculator>,
      public Metricsable<SmartCalculator> {

