        double result = value * value + value;
        return result;
    }

    void setValue(double v) {
        value = v;
        this->invalidateCache();
    }

    std::string name() const { return "SmartCalculator"; }

    void printStats() const {
        this->log("Total calls: " + std::to_string(this->getCallCount()));
    }
};

