public:
    void implementation() { std::cout << "CRTP\n"; }
};

// Virtual - Runtime polymorphism
class VirtualBase {
public:
    virtual void interface() = 0;  // Resolved at runtime via vtable
};

class VirtualDerived : public VirtualBase {
public:
    void interface() override { std::cout << "Virtual\n"; }
};

