public:
    void helper() { std::cout << "Helper\n"; }
};

template <typename T>
class Derived : public Base<T> {
public:
    void method() {
        helper();  // Error: 'helper' not found
    }
};

// ✅ Fix 1: Use this->
template <typename T>
class DerivedFix1 : public Base<T> {
public:
    void method() {
        this->helper();  // ✅ Qualified lookup finds it
    }
};

