Point3D storage[100000];  // Sequential memory

// Accessing nearby objects benefits from cache prefetching
for (int i = 0; i < 100000; ++i) {
    process(&storage[i]);  // ✅ Cache hit rate: ~95%
}

// vs heap allocation (scattered memory)
