  // Direct self-assignment
  v = v;  // this == &other, early return

  // Indirect self-assignment
  Vector<int>& ref = v;
  v = ref;  // this == &other, early return

  // Array self-assignment
  Vector<int> arr[2];
  arr[0] = arr[1];  // Not self-assignment
