    static std::unique_ptr<Sensor> create(Type type) {
        switch (type) {
            case Type::LIDAR:
                return std::make_unique<LidarSensor>();
            case Type::RADAR:
                return std::make_unique<RadarSensor>();
            case Type::CAMERA:
                return std::make_unique<CameraSensor>();
        }
    }

