class Observer {
    shared_ptr<Subject> subject;
public:
    void update() override {
        // What if observer tries to attach another observer?
        subject->attach(make_shared<AnotherObserver>());
        // ❌ DEADLOCK! notify() holds mutex, attach() tries to acquire it
    }
